test('should navigate to home dashboard and verify UI elements load', async ({ page }) => {
  const url = 'https://rahulshettyacademy.com/client/#/dashboard/dash';
  await page.goto(url, { waitUntil: 'networkidle' });

  expect(page.url()).toContain('#/dashboard/dash');
  await expect(page.locator("button[aria-label='HOME']")).toBeVisible();
  await expect(page.locator("[class*='products']")).toBeVisible();
});
